select count(*)
from article
where author_user_id = #{authorUserId}
  and deleted = 0

    and status = #{status}


select count(*)
from article_comment
where user_id = #{userId}

select distinct a.id, a.title, a.summary, a.cover, a.category, a.content, a.status, a.author_user_id, a.review_time, a.reviewer_user_id, a.reject_reason, a.deleted, a.deleted_at, a.deleted_by, a.published_at, a.updated_at, a.views, a.likes, a.comments from article a
inner join article_tag at on at.article_id = a.id
where a.status = 'PUBLISHED' and a.deleted = 0
and at.tag_id = #{tagId}
order by a.published_at desc, a.id desc limit #{limit} offset #{offset}

select id, title, summary, cover, category, content, status, author_user_id, review_time, reviewer_user_id, reject_reason, deleted, deleted_at, deleted_by, published_at, updated_at, views, likes, comments from article where author_user_id = #{authorUserId} and deleted = 0
and status = #{status}
order by updated_at desc, id desc limit #{limit} offset #{offset}

select id, title, summary, cover, category, content, status, author_user_id, review_time, reviewer_user_id, reject_reason, deleted, deleted_at, deleted_by, published_at, updated_at, views, likes, comments from article where deleted = 0
and status = #{status}
order by updated_at desc, id desc limit #{limit} offset #{offset}

select count(*)
from article_like
where article_id = #{articleId}
